import datetime

# Find the earliest Friday the 13th starting from 0001-01-01 (proleptic Gregorian)
date = datetime.date(1, 1, 13)  # start checking the 13th of each month
found = False
while not found:
    if date.weekday() == 4:  # Friday
        print(f'Earliest Friday the 13th: {date.isoformat()} ({date.strftime(\"%A, %B %d, %Y\")})')
        found = True
    else:
        # advance to the 13th of the next month
        if date.month == 12:
            date = date.replace(year=date.year + 1, month=1)
        else:
            date = date.replace(month=date.month + 1)

# Count Friday the 13ths in a full 400-year cycle (the Gregorian calendar repeats every 400 years)
count = 0
for year in range(1, 401):
    for month in range(1, 13):
        if datetime.date(year, month, 13).weekday() == 4:
            count += 1

print(f'Friday the 13ths in a 400-year cycle: {count}')
print(f'Average per year: {count / 400:.4f}')
print(f'Average per month: {count / (400 * 12):.6f} (vs 1/7 = {1/7:.6f})')
